import anthropic

client = anthropic.Anthropic()

def run_agent(
    system: str,
    user_message: str,
    tools: list[dict],
    dispatch: dict,          # {tool_name: callable}
    max_iterations: int = 20,
) -> str:
    """
    Core agentic loop: iterate until the model produces a text-only response
    or max_iterations is reached.
    """
    messages = [{"role": "user", "content": user_message}]
    iterations = 0

    while iterations < max_iterations:
        iterations += 1

        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=1024,
            system=system,
            tools=tools,
            messages=messages,
        )

        # Always append the assistant's full response block list
        messages.append({"role": "assistant", "content": resp.content})

        # Collect any tool calls in this response
        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        if not tool_calls:
            # Model stopped calling tools — return final text
            for block in resp.content:
                if block.type == "text":
                    return block.text
            return ""   # model produced no text (rare)

        # Dispatch each tool call and collect results
        tool_results = []
        for block in tool_calls:
            fn = dispatch.get(block.name)
            if fn is None:
                result = f"Error: unknown tool {block.name!r}"
            else:
                try:
                    result = fn(**block.input)
                except Exception as exc:
                    result = f"Error: {exc}"
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": str(result),
            })

        # Feed results back — next iteration starts
        messages.append({"role": "user", "content": tool_results})

    return f"Stopped after {max_iterations} iterations without a final answer."

# Example usage with a stub tool
import json

def search(query: str) -> str:
    return json.dumps({"results": [{"title": "Paris travel guide", "url": "..."}]})

answer = run_agent(
    system="Answer travel questions using the search tool.",
    user_message="What are the top 3 attractions in Paris?",
    tools=[{
        "name": "search",
        "description": "Search the web for information.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    }],
    dispatch={"search": search},
)
print(answer)

import anthropic
import time

client = anthropic.Anthropic()

def run_agent_with_budgets(
    system: str,
    user_message: str,
    tools: list[dict],
    dispatch: dict,
    max_iterations: int = 20,
    max_wall_seconds: float = 60.0,
    max_consecutive_errors: int = 3,
) -> dict:
    """
    Agentic loop with multiple stop conditions.
    Returns a result dict with status and final text.
    """
    messages = [{"role": "user", "content": user_message}]
    start_time = time.time()
    consecutive_errors = 0

    for iteration in range(1, max_iterations + 1):
        # Wall-clock budget
        elapsed = time.time() - start_time
        if elapsed > max_wall_seconds:
            return {"status": "timeout", "text": None, "iterations": iteration}

        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=1024,
            system=system,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})

        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        if not tool_calls:
            final_text = next(
                (b.text for b in resp.content if b.type == "text"), ""
            )
            return {"status": "complete", "text": final_text, "iterations": iteration}

        # Dispatch and check for error runs
        tool_results = []
        any_error = False
        for block in tool_calls:
            fn = dispatch.get(block.name)
            try:
                result = fn(**block.input) if fn else f"Unknown tool: {block.name}"
                consecutive_errors = 0
            except Exception as exc:
                result = f"Error: {exc}"
                any_error = True

            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": str(result),
            })

        if any_error:
            consecutive_errors += 1
            if consecutive_errors >= max_consecutive_errors:
                return {"status": "error_threshold", "text": None, "iterations": iteration}

        messages.append({"role": "user", "content": tool_results})

    return {"status": "max_iterations", "text": None, "iterations": max_iterations}
